+impl GeminiProvider {
+    /// Construct the full batch-embed URL including API key.
+    #[must_use]
+    pub fn batch_embed_url(&self) -> String {
+        format!(
+            "https://generativelanguage.googleapis.com/v1beta/models/{}:batchEmbedContents?key={}",
+            self.model, self.api_key
+        )
+    }
+}
